(window.courseContentFiles = window.courseContentFiles || {})["000002/0010"] = "<!DOCTYPE html>\r\n<html lang=\"bg\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Белодробна хипертония 2</title>\r\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\r\n  <style>\r\n    body { \r\n      font-family: \"Open Sans\", Arial, sans-serif; \r\n      max-width: 1550px; \r\n      margin: 0.5rem auto; \r\n      padding: 0 1rem; \r\n      line-height: 1.8; \r\n      color: #1f2937; \r\n    }\r\n    h1, h2, h3, h4 { \r\n      font-weight: 600; \r\n      margin-top: 0.8em;\r\n      margin-bottom: 0.3em;\r\n      color: #3a5a40;\r\n    }\r\n    h1 { font-size: 1.5em; }\r\n    h2 { font-size: 1.3em; }\r\n    h3 { font-size: 1.1em; }\r\n    h4 { font-size: 1.05em; }\r\n    h3 + h4 { margin-top: 0.3em; }\r\n    p { \r\n      margin: 0.7em 0; \r\n      white-space: pre-wrap;\r\n    }\r\n    p + ul, p + ol { margin-top: -0.5em; }\r\n    h1 + p, h2 + p, h3 + p, h4 + p,\r\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\r\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \r\n      margin-top: 0.1em; \r\n    }\r\n    ul, ol { \r\n      margin: 0.3em 0; \r\n      padding-left: 1.5em; \r\n    }\r\n    li { margin: 0.15em 0; }\r\n    ul ul { list-style-type: circle; }\r\n    ul ul ul { list-style-type: square; }\r\n    strong { font-weight: 600; }\r\n    em { font-style: italic; }\r\n    code { \r\n      background: rgba(218, 215, 205, 0.3); \r\n      padding: 2px 6px; \r\n      border-radius: 3px; \r\n      font-family: \"Courier New\", monospace; \r\n      font-size: 0.9em; \r\n    }\r\n    pre {\r\n      background: rgba(255, 255, 255, 0.5);\r\n      padding: 12px;\r\n      border-radius: 4px;\r\n      overflow-x: auto;\r\n      margin: 0.5em 0;\r\n      font-family: \"Courier New\", monospace;\r\n    }\r\n    pre code {\r\n      background: none;\r\n      padding: 0;\r\n    }\r\n    blockquote {\r\n      border-left: 3px solid #a3b18a;\r\n      padding-left: 1em;\r\n      margin: 0.5em 0;\r\n      font-style: italic;\r\n      color: #3a5a40;\r\n    }\r\n    table { \r\n      border-collapse: collapse; \r\n      margin: 0.75em 0; \r\n      width: 100%; \r\n      table-layout: auto;\r\n    }\r\n    th, td { \r\n      border: 1px solid rgba(146, 64, 14, 0.35); \r\n      padding: 6px 10px; \r\n      text-align: left; \r\n      vertical-align: top;\r\n      height: 24px;\r\n      line-height: 1.2;\r\n    }\r\n    thead th { \r\n      background: rgba(196, 127, 9, 0.08); \r\n      font-weight: 600; \r\n    }\r\n    tbody tr:nth-child(odd) { \r\n      background: rgba(146, 64, 14, 0.03); \r\n    }\r\n    img { \r\n      max-width: 100%; \r\n      height: auto; \r\n    }\r\n    a { \r\n      color: #a3b18a; \r\n      text-decoration: underline; \r\n    }\r\n    a:hover {\r\n      color: #d97706;\r\n    }\r\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\r\n    li p {\r\n      margin: 0 !important;\r\n      padding: 0 !important;\r\n      display: inline !important;\r\n      line-height: 1 !important;\r\n    }\r\n    /* Prevent nested list paragraph issues */\r\n    li > ul,\r\n    li > ol {\r\n      margin: 0.3em 0 0 0;\r\n      padding-left: 1.5em;\r\n    }\r\n    /* Ensure list structure is clean */\r\n    ul ul, ul ol,\r\n    ol ul, ol ol {\r\n      margin-top: 0.2em;\r\n      padding-left: 1.5em;\r\n    }\r\n    @media (max-width: 768px) {\r\n      body {\r\n        max-width: 100%;\r\n        margin: 0.5rem 0;\r\n        padding: 0 0.5rem;\r\n        font-size: 16px;\r\n      }\r\n      h1 { font-size: 1.3em; }\r\n      h2 { font-size: 1.1em; }\r\n      h3 { font-size: 1em; }\r\n      p { margin: 0.5em 0; }\r\n      ul, ol { padding-left: 1.2em; }\r\n      li { margin: 0.1em 0; }\r\n      table { font-size: 0.9em; }\r\n      th, td { padding: 4px 6px; }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n<h1 style=\"font-size: 1.5em;\">Белодробна (пулмонална) хипертония</h1><h3 style=\"font-size: 1.1em;\">Обща характеристика</h3><ul><li style=\"font-size: 1em;\"><strong>Пулмоналната хипертония (ПХ)</strong> е заболяване, което се манифестира с дискретни симптоми, което води до забавяне на диагнозата.</li><li style=\"font-size: 1em;\"><strong>Нелекувана</strong>, тя се характеризира с прогресивно увеличение на <strong>белодробното съдово съпротивление</strong>, <strong>десностранна сърдечна недостатъчност (ДСН)</strong> и смърт.</li><li style=\"font-size: 1em;\">Преживяемостта на пациенти с <strong>идиопатична пулмонална артериална хипертония (ИПАХ)</strong> е <strong>2.8 години</strong> от деня на поставяне на диагнозата.</li><li style=\"font-size: 1em;\">Смъртта е тясно свързана с прогресивно влошаване на <strong>хемодинамиката</strong>.</li><li style=\"font-size: 1em;\">През последните години в лечението на <strong>пулмоналната артериална хипертония (ПАХ)</strong> бяха регистрирани значителни успехи, касаещи преживяемостта и качеството на живот на пациентите.</li></ul><h3 style=\"font-size: 1.1em;\"><hr>Дефиниция</h3><ul><li style=\"font-size: 1em;\"><strong>Пулмоналната хипертония</strong> се дефинира като повишено <strong>средно налягане в белодробната артерия (mPAP)</strong> &gt; <strong>25 mmHg </strong>в покой, при дясната сърдечна катеризация.</li><li style=\"font-size: 1em;\"><strong>Нормални стойности</strong> на <strong>mPAP</strong> са <strong>14 ± 3 mmHg</strong>, като за горна граница на нормата се приемат стойности от <strong>20 mmHg</strong>.</li><li style=\"font-size: 1em;\"><strong>„Сивата зона\"</strong> (стойности между 20-25 mmHg) все още не е достатъчно дефинирана.</li><li style=\"font-size: 1em;\">Пациенти, представящи се със стойности на <strong>mPAP</strong> между 21 и 24 mmHg, трябва да бъдат подлагани на <strong>допълнителни изследвания</strong>.</li><li style=\"font-size: 1em;\">Описани са повече от 30 форми, обобщени в <strong>5 диагностични категории</strong>.</li><li style=\"font-size: 1em;\">Белодробно сърце:&nbsp;<p style=\"font-size: 1em;\"><b>Хипертрофия </b>и/или <b>дилатация </b>на дясната камера на сърцето </p><p style=\"font-size: 1em;\">в резултат на нарушение (структура, функция, циркулация) </p><p style=\"font-size: 1em;\">на белия дроб протичащи с белодробна хипертония.</p></li></ul><h4 style=\"font-size: 1.05em;\"><span style=\"font-size: inherit; white-space-collapse: preserve;\"><hr>Епидемиология:</span></h4><p style=\"font-size: 1em;\"></p><ul><li style=\"font-size: 1em;\"><span style=\"font-size: inherit; white-space-collapse: preserve;\"><p style=\"font-size: 1em;\">78.7% с болест на лявото сърце</p></span></li><li style=\"font-size: 1em;\"><span style=\"font-size: inherit; white-space-collapse: preserve;\"><p style=\"font-size: 1em;\">9,7% с белодробни заболявания и хипоксия</p></span></li><li style=\"font-size: 1em;\"><span style=\"font-size: inherit; white-space-collapse: preserve;\"><p style=\"font-size: 1em;\">4,2% с БАХ</p></span></li><li style=\"font-size: 1em;\"><span style=\"font-size: inherit; white-space-collapse: preserve;\"><p style=\"font-size: 1em;\">0,6% група 4</p></span></li><li style=\"font-size: 1em;\"><span style=\"font-size: inherit; white-space-collapse: preserve;\"><p style=\"font-size: 1em;\">при 6,8% не може да се намери причина</p></span></li></ul><h3 style=\"font-size: 1.1em;\"><hr>Клинична класификация на белодробната хипертония</h3><p style=\"font-size: 1em;\"><b>1. Пулмонална артериална хипертония</b> (различно определение от пулмонална хипертония)</p><ul><li style=\"font-size: 1em;\"><strong>1.1. Идиопатична</strong></li><li style=\"font-size: 1em;\"><strong>1.2. Наследствена:</strong></li><ul><li style=\"font-size: 1em;\">BMPR2-мутации</li><li style=\"font-size: 1em;\">ALK-1, endoglin мутации (с или без хередитарна хеморагична телеангиектазия<b>)</b></li><li style=\"font-size: 1em;\">Непознати мутации</li></ul><li style=\"font-size: 1em;\"><strong>1.3. Предизвикана от медикаменти и токсини</strong></li><li style=\"font-size: 1em;\"><strong>1.4. Асоциирана с:</strong></li><ul><li style=\"font-size: 1em;\">Болести на съединителната тъкан</li><li style=\"font-size: 1em;\">HIV инфекция</li><li style=\"font-size: 1em;\">Портална хипертония</li><li style=\"font-size: 1em;\">Вродени сърдечни заболявания</li><li style=\"font-size: 1em;\">Хронична хемолитична анемия</li></ul><li style=\"font-size: 1em;\"><strong>1.5. Персистираща пулмонална хипертония на новороденото</strong></li></ul><p style=\"font-size: 1em;\"><b>1'. Белодробна вено-оклузивна болест и/или белодробна капилярна хемангиомиоматоза</b></p><p style=\"font-size: 1em;\"><b>2. Пулмонална хипертония при наличие на левостранни сърдечни заболявания</b></p><ul><li style=\"font-size: 1em;\">Със систолна дисфункция</li><li style=\"font-size: 1em;\">С диастолна дисфункция</li><li style=\"font-size: 1em;\">При заболявания на сърдечните клапи</li></ul><p style=\"font-size: 1em;\"><b>3. Пулмонална хипертония, като последица от белодробни заболявания и/или хипоксия</b></p><ul><li style=\"font-size: 1em;\">ХОББ</li><li style=\"font-size: 1em;\">Интерстициални белодробни болести</li><li style=\"font-size: 1em;\">Други белодробни заболявания, протичащи със смесени рестриктивно/обструктивни нарушения</li><li style=\"font-size: 1em;\">Нарушения на дишането по време на сън</li><li style=\"font-size: 1em;\">Заболявания протичащи с алвеоларна хиповентилация</li><li style=\"font-size: 1em;\">Хронична експозиция на големи височини</li><li style=\"font-size: 1em;\">Абнормно развитие</li></ul><p style=\"font-size: 1em;\"><b>4. Хронична тромбоемболична пулмонална хипертония</b></p><p style=\"font-size: 1em;\"><b>5. Пулмонална хипертония с неясни и/или мултифакторни механизми на развитие</b></p><ul><li style=\"font-size: 1em;\"><strong>При хематологични заболявания:</strong> <p style=\"font-size: 1em;\">хронична хемолитична анемия, </p>миелопролиферативни заболявания, спленектомия</li><li style=\"font-size: 1em;\"><strong>При системни заболявания:</strong> саркоидоза, белодробна хистиоцитоза, лимфангиолейомиоматоза, неврофиброматоза, васкулити</li><li style=\"font-size: 1em;\"><strong>При метаболитни нарушения:</strong> заболявания, свързани с нарушения на обмяната на гликоген, болест на Gaucher, заболявания на щитовидната жлеза</li><li style=\"font-size: 1em;\"><strong>Други:</strong> обструкция от туморни клетки, фиброзиращ медиастинит, хронична бъбречна недостатъчност и хемодиализа</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Етиология, рискови фактори</h3><h4 style=\"font-size: 1.05em;\">Етиология и Рискови фактори</h4><ul><li style=\"font-size: 1em;\"><strong>Медикаменти и токсини:</strong></li><ul><li style=\"font-size: 1em;\">Наркотични и токсични вещества като кокаин, (мет)амфетамин, L-триптофан.</li><li style=\"font-size: 1em;\">Химиотерапевтици като Mitomycin С.</li></ul><li style=\"font-size: 1em;\"><strong>Ревматични заболявания:</strong> Често <strong>ПАХ</strong> се асоциира с тях.</li><li style=\"font-size: 1em;\"><strong>HIV инфекция:</strong> <strong>ПАХ</strong> се среща 600-пъти по-често при пациенти с <strong>HIV инфекция</strong>.</li><li style=\"font-size: 1em;\"><strong>Чернодробно заболяване/Портопулмонална хипертония:</strong> Установява се при 2-10% от пациентите.</li><li style=\"font-size: 1em;\"><strong>Вродени сърдечни пороци:</strong> При пациенти с коригирани или некоригирани сърдечни пороци с наличие на <strong>шънт</strong>.</li><li style=\"font-size: 1em;\"><strong>Хронична хемолитична анемия:</strong> Включва сърповидно-клетъчна анемия, таласемия, наследствена сфероцитоза, стоматоцитоза и микроангиопатична хемолитична анемия.</li><li style=\"font-size: 1em;\"><strong>Белодробна венооклузивна болест и/или белодробна капилярна хемангиоматоза:</strong> Наблюдават се при по-малко от <strong>10%</strong> от болните с <strong>ИПАХ</strong>. Лечението с вазоактивни медикаменти при тези пациенти може да доведе до развитието на <strong>белодробен оток</strong>.</li><li style=\"font-size: 1em;\"><strong>Заболяване на митралната клапа:</strong> <strong>ПХ</strong> може да се установи при почти всички пациенти с тежко симптоматично заболяване на <strong>митралната клапа</strong>.</li><li style=\"font-size: 1em;\"><strong>Аортна стеноза:</strong> До <strong>65%</strong> от тези със симптомна <strong>аортна стеноза</strong>.</li><li style=\"font-size: 1em;\"><strong>Напреднал ХОББ:</strong> <strong>ПХ</strong> е с висока честота на разпространение <strong>&gt; 50%</strong>.</li><li style=\"font-size: 1em;\"><strong>Интерстициални белодробни заболявания:</strong> Честотата се изчислява между <strong>32 и 39%</strong>.</li><li style=\"font-size: 1em;\"><strong>Хронична тромбоемболична пулмонална хипертония:</strong> Разпространението е до <strong>3,8%</strong> сред преживелите <strong>остър белодробен тромбоемболизъм</strong>.</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Физиология на белодробната циркулация. Регулация на съдовия тонус</h3><ul><li style=\"font-size: 1em;\"><strong>Белодробният кръвоток</strong> се отличава в значима степен от кръвотока на другите органи.</li><li style=\"font-size: 1em;\">Съдовата система на белия дроб е система на <strong>ниско налягане</strong>.</li><li style=\"font-size: 1em;\">Артериалните налягания и съдовото съпротивление са само около една осма от стойността на тези в <strong>голямото кръвообръщение</strong>.</li><li style=\"font-size: 1em;\">Въздействие върху <strong>съдовия тонус</strong> оказват <strong>вазодилататорни</strong> и <strong>вазоконстрикторни медиатори</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Вазодилататорни медиатори</h4><ul><li style=\"font-size: 1em;\">Ниският мускулен съдов тонус на белодробната васкуларна система се понижава допълнително при натоварване посредством активна секреция на <strong>вазодилататорни медиатори</strong>, секретирани преди всичко от <strong>съдовия ендотел</strong>.</li><li style=\"font-size: 1em;\">Централна роля имат произвежданите от <strong>съдовия ендотел</strong> медиатори:</li><ul><li style=\"font-size: 1em;\"><strong>азотен окис (NO)</strong></li><li style=\"font-size: 1em;\"><strong>простациклин (PGI2)</strong></li></ul><li style=\"font-size: 1em;\"><strong>Атриалният натриуретичен пептид (ANP)</strong> също е вазодилататор и взема участие в понижаването на <strong>белодробния съдов тонус</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Вазоконстрикторни медиатори</h4><ul><li style=\"font-size: 1em;\">До момента са идентифицирани следните белодробни вазоконстриктори:</li><ul><li style=\"font-size: 1em;\"><strong>ангиотензин II</strong></li><li style=\"font-size: 1em;\"><strong>ендотелин</strong></li><li style=\"font-size: 1em;\"><strong>тромбоксан А2</strong></li><li style=\"font-size: 1em;\"><strong>цистеиниллевкотриени</strong></li></ul><li style=\"font-size: 1em;\">Освобождаването на <strong>вазоактивните медиатори</strong> се осъществява в резултат на възпалителни процеси в белия дроб или при механично натоварване на <strong>съдовите стени</strong>.</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Патофизиология</h3><p style=\"font-size: 1em;\">Развитието на <strong>пулмоналната хипертония</strong> може да се основава механично на следните причини:</p><ul><li style=\"font-size: 1em;\">Намаляване на диаметъра на съдовете (<strong>обструкция</strong>)</li><li style=\"font-size: 1em;\">Загуба на съдове (<strong>Облитерация</strong>)</li><li style=\"font-size: 1em;\">Понижаване на <strong>съдовата еластичност</strong></li></ul><h4 style=\"font-size: 1.05em;\">Патологични механизми</h4><p style=\"font-size: 1em;\">Основните механизми, които водят до патологични съдови промени и съдови реакции, са обобщени както следва:</p><ul><li style=\"font-size: 1em;\"><strong>Рефлекс на вазоконстрикция:</strong></li><ul><li style=\"font-size: 1em;\">Важен отключващ фактор за <strong>ПХ</strong> е непрекъснатото активиране на <strong>хипоксичния вазоконстрикторен рефлекс</strong>.</li><li style=\"font-size: 1em;\"><strong>Алвеоларната хипоксия</strong> може да бъде екстрапулмонално обусловена (при жители на високопланински региони, централни/обструктивни нарушения в регулацията на дишането, деформации на гръдната стена и др.) и обичайно има отношение към механизма на <strong>алвеоларна хиповентилация</strong> при обструктивни вентилационни нарушения.</li><li style=\"font-size: 1em;\">Реверзибелната в началните периоди <strong>съдова констрикция</strong> с времето и при персистирането на <strong>алвеоларна хипоксия</strong> се замества от феномена на <strong>съдово ремоделиране</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Механична обструкция:</strong></li><ul><li style=\"font-size: 1em;\">При <strong>ПХ</strong> в резултат от хронично-рецидивиращи <strong>микроемболи</strong> патофизиологичният механизъм е свързан с ограничаването на <strong>тромболитичния клирънс</strong> с последваща организация на <strong>облитериралия тромботичен материал</strong>.</li><li style=\"font-size: 1em;\">При <strong>хронично-персистираща белодробна емболия</strong> патогенетичният проблем се състои в непълното разграждане на тромба.</li><li style=\"font-size: 1em;\">И в двата случая имфламаторна реакция в участъка на емболизация може да доведе до допълнителна реакция на <strong>вазоконстрикция</strong>.</li><li style=\"font-size: 1em;\">В останалите перфузирани съдови области се развиват допълнителни хронични процеси на преустройство, които водят до хронична прогресия и повишаване на <strong>белодробното налягане</strong>.</li></ul></ul><h4 style=\"font-size: 1.05em;\">Патоморфология на съдовото ремоделиране</h4><ul><li style=\"font-size: 1em;\">Патофизиологичните промени на белодробните съдове при <strong>хронична пулмонална хипертония</strong> могат да бъдат локализирани <strong>прекапилярно</strong>, <strong>посткапилярно</strong>, а в редки случаи и в <strong>капилярното легло</strong>.</li><li style=\"font-size: 1em;\">При всички форми на <strong>хронична пулмонална хипертония</strong> големите централни съдове са разширени поради високото налягане.</li><li style=\"font-size: 1em;\">За разлика от това луменът на <strong>малките съдове</strong> е намален поради процесите на преустройство на <strong>съдовата стена</strong>. На този феномен се основава понятието <strong>съдово ремоделиране</strong>.</li><li style=\"font-size: 1em;\">При моделирането на <strong>съдовата стена</strong> по време на развитието на <strong>хроничната пулмонална хипертония</strong> се достига до следните хистологични феномени:</li><ul><li style=\"font-size: 1em;\"><strong>Фиброза на интимата</strong></li><li style=\"font-size: 1em;\"><strong>Хипертрофия на медията</strong></li><li style=\"font-size: 1em;\"><strong>Де-ново Мускуларизация</strong></li></ul></ul><h4 style=\"font-size: 1.05em;\">Хуморални ефектори</h4><p style=\"font-size: 1em;\">Медиаторите, вземащи участие в преустройството на <strong>съдовата стена</strong>, могат да се разделят на 3 групи:</p><ul><li style=\"font-size: 1em;\"><strong>Първа група (Вазоконстриктивен и митогенен профил):</strong></li><ul><li style=\"font-size: 1em;\">Упражняват митогенно въздействие върху компонентите на <strong>съдовата стена</strong>.</li><li style=\"font-size: 1em;\">Прототип на тези субстанции са <strong>ендотелина</strong>, <strong>тромбоксан А2</strong>, <strong>тромбин</strong>, <strong>левкотриени</strong> и <strong>активиращият тромбоцитите фактор</strong>.</li><li style=\"font-size: 1em;\">При различните форми на <strong>хронична пулмонална хипертония</strong> и ремоделиране на <strong>съдовата стена</strong> е доказано повишено синтезиране на тези субстанции.</li></ul><li style=\"font-size: 1em;\"><strong>Втора група (Пролиферативни пептиди):</strong></li><ul><li style=\"font-size: 1em;\">Обхваща пролиферативни пептиди от цитотоксичната система като <strong>туморнекротизиращ фактор</strong>, <strong>интерлевкини</strong> и различни <strong>растежни фактори</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Трета група (Вазодилататорно и антипролиферативно действие):</strong></li><ul><li style=\"font-size: 1em;\">Това са <strong>PGI2</strong>, <strong>ANP</strong> и <strong>NO</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Нарушаването на равновесието</strong> между горните групи медиатори в полза на пролиферативните фактори се разглежда като <strong>патогенетичен механизъм</strong> за <strong>ремоделиране на съдовата стена</strong>.</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Cor pulmonale:&nbsp;</h3><p style=\"font-size: 1em;\"><span style=\"font-weight: normal;\"><font color=\"#3a5a40\">Дефиниция:</font></span></p><p style=\"font-size: 1em;\">Хипетрофия и дилатация на дясна камера:</p><p style=\"font-size: 1em;\"></p><ul><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\">В резултат на Пулмонална Хипертония</p></li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\">В резултат от заболявания на белодробния </p><p style=\"font-size: 1em;\">паренхим и/или гръдната стена и/или </p><p style=\"font-size: 1em;\">белодробната съдова система</p></li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\">Със или без данни за СН</p></li><li style=\"font-size: 1em;\"><u><p style=\"font-size: 1em;\">При изключване на причина за наличие на</p><p style=\"font-size: 1em;\">вродено сърдечно заболяване или </p></u><p style=\"font-size: 1em;\"><u>заболяване на лявото сърце</u>.</p></li></ul><p style=\"font-size: 1em;\"><font color=\"#3a5a40\">Класификация:</font></p><p style=\"font-size: 1em;\"></p><ul style=\"font-size: inherit;\"><li style=\"font-size: 1em;\">Остро/остра</li><li style=\"font-size: 1em;\">Хронично/хронична</li></ul><h3 style=\"font-size: 1.1em;\"><hr>Клинична картина</h3><h4 style=\"font-size: 1.05em;\">Симптоми</h4><ul><li style=\"font-size: 1em;\">Пациентите с <strong>пулмонална хипертония</strong> се представят с типични, но неспецифични за заболяването симптоми.</li><li style=\"font-size: 1em;\">Кардинални симптоми са <strong>диспнея при физически усилия</strong> и <strong>умора</strong>.</li><li style=\"font-size: 1em;\"><strong>Синкоп</strong> или <strong>пресинкоп</strong> са често първоначална манифестация на <strong>деснокамерната сърдечна декомпенсация</strong>, като тези симптоми са <strong>късна проява</strong> на заболяването.</li><li style=\"font-size: 1em;\">Оплакванията могат да включват:</li><ul><li style=\"font-size: 1em;\">Увеличаване на <strong>задуха</strong></li><li style=\"font-size: 1em;\">Намалена <strong>работоспособност</strong></li><li style=\"font-size: 1em;\"><strong>Сърцебиене</strong> и <strong>болка в гърдите</strong></li><li style=\"font-size: 1em;\">Загуба на <strong>апетит</strong></li><li style=\"font-size: 1em;\"><strong>Болка в гърдите</strong></li><li style=\"font-size: 1em;\"><strong>Суха кашлица</strong></li><li style=\"font-size: 1em;\"><strong>Виене на свят</strong></li><li style=\"font-size: 1em;\"><strong>Синкопи</strong>, а понякога и <strong>епилептични припадъци</strong></li></ul></ul><table><tbody><tr><td style=\"font-size: 1em;\">Клинични симптоми на Пулмонална хипертония</td><td style=\"font-size: 1em;\">Начална манифестация (%)</td><td style=\"font-size: 1em;\">Поставяне на диагноза (%)</td></tr><tr><td style=\"font-size: 1em;\">Задух при физически усилия</td><td style=\"font-size: 1em;\">60</td><td style=\"font-size: 1em;\">98</td></tr><tr><td style=\"font-size: 1em;\">Умора</td><td style=\"font-size: 1em;\">20</td><td style=\"font-size: 1em;\">73</td></tr><tr><td style=\"font-size: 1em;\">Ангинозни оплаквания</td><td style=\"font-size: 1em;\">7</td><td style=\"font-size: 1em;\">47</td></tr><tr><td style=\"font-size: 1em;\">Колапс, Синкоп</td><td style=\"font-size: 1em;\">12</td><td style=\"font-size: 1em;\">&gt;41</td></tr><tr><td style=\"font-size: 1em;\">Оток по подбедриците</td><td style=\"font-size: 1em;\">3</td><td style=\"font-size: 1em;\">37</td></tr><tr><td style=\"font-size: 1em;\">Палпитации</td><td style=\"font-size: 1em;\">5</td><td style=\"font-size: 1em;\">33</td></tr></tbody></table><p style=\"font-size: 1em;\"><b>Други въпроси за анамнеза:</b></p><p style=\"font-size: 1em;\"></p><ul><li style=\"font-size: 1em;\">Артериосклероза?</li><li style=\"font-size: 1em;\">Сърдечно заболяване?</li><li style=\"font-size: 1em;\">Лекарства?</li><li style=\"font-size: 1em;\">От кога?</li><li style=\"font-size: 1em;\">Белодробни заболявания?</li><li style=\"font-size: 1em;\">Медикаменти? Наркотици? Токсини?</li><li style=\"font-size: 1em;\">Известни вродени болести на сърцето?</li><li style=\"font-size: 1em;\">Анамнеза на пътуванията (шистозомиаза)?</li><li style=\"font-size: 1em;\">Чернодробно заболяване?</li><li style=\"font-size: 1em;\">Тромбоза?</li><li style=\"font-size: 1em;\">Белодробнаемболия?</li><li style=\"font-size: 1em;\">Коагулационни нарушения?</li><li style=\"font-size: 1em;\">Заболяване на щитовидната жлеза?</li><li style=\"font-size: 1em;\">Бъбречно заболяване?</li><li style=\"font-size: 1em;\">Рак? Как се третира?</li><li style=\"font-size: 1em;\">Медикаменти за отслабване? Какво?</li><li style=\"font-size: 1em;\">ХИВ?</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Диагноза</h3><h4 style=\"font-size: 1.05em;\">Обективно изследване</h4><ul><li style=\"font-size: 1em;\">Обективното изследване, което документира характерни промени, доказващи наличието на манифестна <strong>десностранна сърдечна недостатъчност</strong>, се наблюдават обикновено при пациенти с изявена и <strong>напреднала пулмонална хипертония</strong>.</li><li style=\"font-size: 1em;\"><strong>При оглед се установяват:</strong></li><ul><li style=\"font-size: 1em;\">Пулсации на <strong>югуларните вени</strong>, положителен <strong>хепатоюгуларен рефлукс</strong>, патологични пулсации в ляво парастернално</li><li style=\"font-size: 1em;\">Периферен застой</li><li style=\"font-size: 1em;\"><strong>Цианоза</strong></li><li style=\"font-size: 1em;\"><strong>Отоци по подбедриците</strong></li></ul><li style=\"font-size: 1em;\"><strong>При палпация:</strong></li><ul><li style=\"font-size: 1em;\"><strong>Хепатомегалия</strong></li><li style=\"font-size: 1em;\"><strong>Асцит</strong></li></ul><li style=\"font-size: 1em;\"><strong>При аускултация:</strong></li><ul><li style=\"font-size: 1em;\">Акцентуиран, <strong>раздвоен втори тон</strong></li><li style=\"font-size: 1em;\">Систолен шум на изтласкване на <strong>пулмоналната клапа</strong></li><li style=\"font-size: 1em;\">Диастолен шум на <strong>пулмонална регургитация</strong> (на <strong>Graham Stell</strong>)</li><li style=\"font-size: 1em;\">Систолен шум на <strong>трикуспидална инсуфициенция</strong></li><li style=\"font-size: 1em;\"><strong>Деснокамерен Т3 галоп</strong> при наличие на <strong>ДК помпена дисфункция</strong></li></ul><li style=\"font-size: 1em;\">Перкусията и аускултацията на белите дробове обичайно са <strong>нормални</strong>, ако липсва белодробно заболяване.</li><li style=\"font-size: 1em;\">При обективното изследване трябва да се обърне внимание за наличие на белези на <strong>основно заболяване</strong>, което би могло да има отношение към <strong>ПАХ</strong> (напр. патологични шумове на сърцето, ставни и кожни лезии или заболявания на черния дроб и кожата).</li></ul><h4 style=\"font-size: 1.05em;\">Инструментално изследване</h4><ul><li style=\"font-size: 1em;\">При наличие на оплаквания от <strong>задух</strong> се назначава <strong>функционално изследване на дишането (ФИД)</strong> и <strong>кръвно-газов анализ (КГА)</strong>.</li><li style=\"font-size: 1em;\">При нормални или почти нормални стойности на тези изследвания би трябвало да се мисли и за <strong>белодробна съдова болест</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Рентгенография на гръдна клетка - <a href=\"https://radiopaedia.org/articles/pulmonary-hypertension-1?lang=us\">Radiopedia</a></h4><ul><li style=\"font-size: 1em;\">При <strong>90%</strong> от пациентите с <strong>ИПАХ</strong> рентгенографията на <strong>гръдна клетка</strong> е абнормна към момента на поставяне на диагнозата.</li><li style=\"font-size: 1em;\">Може да даде допълнителни доказателства за <strong>ПАХ</strong> като <strong>кардиомегалия</strong>, подчертаване на сегмента на <strong>белодробната артерия</strong> и диаметър на <strong>дясната долнолобарна пулмонална артерия</strong> &gt; <strong>16 mm</strong>.</li><li style=\"font-size: 1em;\">При авансирало заболяване, могат да бъдат установени увеличаване на <strong>дясното предсърдие (ДП)</strong> и <strong>дясната камера (ДК)</strong>.</li><li style=\"font-size: 1em;\">Рентгенографията дава възможност за изключване на подлежащо <strong>белодробно заболяване</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Електрокардиография</h4><ul><li style=\"font-size: 1em;\">Установяват се данни, суспектни за <strong>пулмонална хипертония</strong>, като белези на:</li><ul><li style=\"font-size: 1em;\"><strong>ДК хипертрофия</strong> (установява се при 87% от пациентите)</li><li style=\"font-size: 1em;\"><strong>ДК обременяване</strong></li><li style=\"font-size: 1em;\"><strong>ДП дилатация</strong></li><li style=\"font-size: 1em;\">Изместване на сърдечната ос <strong>на дясно</strong> (при 79%)</li><li style=\"font-size: 1em;\">(Непълен) <strong>десен бедрен блок</strong> (при 50%)</li></ul><li style=\"font-size: 1em;\">При тежка <strong>пулмонална хипертония</strong> могат да се наблюдават и вторични реполаризационни промени с <strong>низходяща депресия на ST-сегмента</strong>, претерминална <strong>отрицателна Т-вълна</strong>.</li><li style=\"font-size: 1em;\">Наличието на <strong>P-pulmonale</strong> е относително рядък белег.</li><li style=\"font-size: 1em;\">При съмнение за <strong>ПАХ</strong> или при неясни оплаквания трябва да бъде осъществено <strong>ЕХОКГ изследване</strong>, като първа стъпка в диагностичния алгоритъм.</li></ul><h4 style=\"font-size: 1.05em;\">Установяване на причините за ПХ</h4><ul><li style=\"font-size: 1em;\">Целта на диагностичния процес е <strong>идентифициране/изключване на причините</strong>, довели до развитието на <strong>ПХ</strong>.</li><li style=\"font-size: 1em;\"><strong>Най-честите причини</strong> за постпървична „вторична\", <strong>пулмонална хипертония</strong> са:</li><ul><li style=\"font-size: 1em;\">Заболяванията на <strong>белия дроб</strong> и <strong>дихателните пътища</strong>.</li><li style=\"font-size: 1em;\">Заболяванията на <strong>лявото сърце</strong>.</li><li style=\"font-size: 1em;\">Нарушенията на съня, свързани с дишането.</li><li style=\"font-size: 1em;\">Сърдечни пороци с наличие на <strong>шънт</strong>.</li></ul><li style=\"font-size: 1em;\">Те могат да бъдат доказани чрез:</li><ul><li style=\"font-size: 1em;\">Оценка на белодробната функция</li><li style=\"font-size: 1em;\">Полисомнография</li><li style=\"font-size: 1em;\">Високо разделителна компютърна томография (ВРКТ)</li><li style=\"font-size: 1em;\">Ехокардиография</li><li style=\"font-size: 1em;\">Трансесофагеална ЕХОКГ</li></ul><li style=\"font-size: 1em;\"><strong>За идентифициране на портална хипертензия:</strong></li><ul><li style=\"font-size: 1em;\">Абдоминална <strong>ехография</strong> в допълнение към лабораторните изследвания.</li></ul><li style=\"font-size: 1em;\"><strong>За установяване на заболявания на съединителната тъкан</strong> (склеродермия, смесена съединително тъканна болест, лупус еритематодес, ревматоиден артрит):</li><ul><li style=\"font-size: 1em;\">Задължително е изследването на различни антитела: <strong>SCL-70</strong>, <strong>антицентромерни антитела</strong>, <strong>ANA скрининг</strong>, <strong>ревматоиден фактор</strong> и др.</li></ul><li style=\"font-size: 1em;\">В алгоритъма се включва изследване за <strong>HIV</strong> и <strong>серология за хепатит</strong>.</li><li style=\"font-size: 1em;\">Диагнозата <strong>идиопатична пулмонална артериална хипертония</strong> е <strong>диагноза на изключването</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Биохимични маркери</h4><ul><li style=\"font-size: 1em;\">За <strong>пулмоналната хипертония</strong> липсват специфични лабораторни тестове.</li><li style=\"font-size: 1em;\"><strong>Недостатъчността на дясната камера</strong> е най-честата причина за смърт при пациенти с <strong>ПАХ</strong>.</li><li style=\"font-size: 1em;\">Плазмените нива на <strong>натриуретичните пептиди ANP</strong>, <strong>BNP</strong>, <strong>NT-proBNP</strong> отразяват тежестта на <strong>ДК дисфункция</strong>.</li><li style=\"font-size: 1em;\">Базово средно ниво на <strong>BNP 150 pg/mL</strong> разграничава пациенти с добра или лоша прогноза.</li></ul><h4 style=\"font-size: 1.05em;\">Белодробни функционални тестове</h4><ul><li style=\"font-size: 1em;\"><strong>Белодробните функционални тестове</strong> и измерването на <strong>артериалните кръвни газове</strong> имат за цел идентифицирането на заболяване на <strong>дихателните пътища</strong> или <strong>белодробния паренхим</strong>.</li><li style=\"font-size: 1em;\">При липса на такова заболяване <strong>спирометрията</strong> и <strong>цялотелесната плетизмография</strong> при <strong>белодробна хипертония</strong> обикновено са нормални.</li><li style=\"font-size: 1em;\"><strong>Полисомнографията</strong> изключва наличието на <strong>обструктивна сънна апнея</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Ехокардиография и доплер ехокардиография</h4><ul><li style=\"font-size: 1em;\"><strong>Ехокардиографията</strong> е централен метод за диагнозата на <strong>пулмоналната хипертония</strong>.</li><li style=\"font-size: 1em;\">Служи не само за изключване или откриване на заболяване на <strong>лявата камера</strong>, но позволява извършването на <strong>оценка на белодробното артериално налягане</strong> и <strong>ДК функция</strong>.</li><li style=\"font-size: 1em;\"><strong>Разширените дясна камера или дясно предсърдие</strong>, <strong>намалената деснокамерна помпена функция</strong>, <strong>значимата трикуспидална инсуфициенция</strong> и наличието на <strong>перикарден излив</strong> са важни показатели за <strong>лоша прогноза</strong> при <strong>ПАХ</strong>.</li><li style=\"font-size: 1em;\">Към полуинвазивните методи за откриване на <strong>вродени сърдечни пороци</strong> или <strong>отворен foramen ovale</strong> се причислява и <strong>трансесофагеалната ехокардиография</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Вентилационно/перфузионна сцинтиграфия</h4><ul><li style=\"font-size: 1em;\">Извършва се при пациенти с <strong>ПХ</strong> с оглед установяване на потенциално лечима <strong>ХПТЕПХ</strong>.</li><li style=\"font-size: 1em;\">Нормален образ или ниска вероятност при <strong>вентилационно-перфузионна белодробна сцинтиграфия</strong> изключват <strong>ХПТЕПХ</strong> с чуствителност <strong>90-100%</strong> и специфичност <strong>94-100%</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Компютърна томография, магнитно резонансна томография и белодробна ангиография</h4><ul><li style=\"font-size: 1em;\"><strong>Мултидетекторната спирална компютърна томография (MSCT)</strong> и <strong>магнитно-резонансната томография (MRT)</strong> играят важна роля в изясняване на диагнозата <strong>ПХ</strong>, както и за осъществяване на функционална оценка на <strong>пулмоналната хипертония</strong> и последващата я <strong>дясна сърдечна недостатъчност</strong>.</li><li style=\"font-size: 1em;\"><strong>MSCT</strong> е подходящо средство за откриване и диференциране на промени в <strong>белодробния паренхим</strong>.</li><li style=\"font-size: 1em;\">Днешните техники позволяват отлична визуализация на <strong>централните белодробни артерии</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Тестове с натоварване</h4><ul><li style=\"font-size: 1em;\">С оглед обективизиране на ежедневното натоварване днес се прилага <strong>6-минутен тест с ходене</strong> – елементарен, евтин, възпроизводим и добре станартизиран тест.</li></ul><h4 style=\"font-size: 1.05em;\">Дясна сърдечна катетеризация и тест за реверзибилност (вазореактивност)</h4><ul><li style=\"font-size: 1em;\"><strong>Дясната сърдечна катетеризация</strong> е <strong>задължително изследване</strong> за поставяне на диагноза <strong>ПАХ</strong>, с оглед:</li><ul><li style=\"font-size: 1em;\">Окончателното количествено определяне на <strong>белодробната хемодинамика</strong>.</li><li style=\"font-size: 1em;\">Тестване на <strong>вазореактивността</strong> върху <strong>белодробната циркулация</strong>.</li><li style=\"font-size: 1em;\">Вземане на решение за <strong>медикаментозно лечение</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Тест за вазореактивност:</strong> Извършва се в края на основните измервания.</li><ul><li style=\"font-size: 1em;\">Използва се вдишване на <strong>азотен окис (NO)</strong> или се инжектира <strong>Iloprost</strong>, или <strong>adenosine</strong>.</li><li style=\"font-size: 1em;\">Целта е да се предскаже отговорът към лечението с <strong>блокери на калциевите канали</strong>.</li><li style=\"font-size: 1em;\"><strong>Положителен тест</strong> (\"<strong>Реагиращи, респондери</strong>\") се счита <strong>понижаването на PAP &gt; 10 mmHg</strong> до стойности <strong>&lt;40 mmHg</strong>, при повишаване или липса на промяна в <strong>СО</strong>.</li></ul><li style=\"font-size: 1em;\">Пациентите с <strong>позитивен вазореактивен тест</strong> с по-голяма вероятност отговарят на лечението с <strong>високи дози блокери на калциевите канали</strong>.</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Оценка на тежестта и прогноза</h3><h4 style=\"font-size: 1.05em;\">Функционален клас на пулмоналната хипертония (модификация по WHO 1998)</h4><table><tbody><tr><td style=\"font-size: 1em;\">СЗО Клас</td><td style=\"font-size: 1em;\">Описание</td></tr><tr><td style=\"font-size: 1em;\"><strong>Клас I</strong></td><td style=\"font-size: 1em;\">Пациенти с <strong>ПХ</strong>, но <strong>без ограничаване на физическата активност</strong>, липса на диспнея, умора, гръдна болка или синкоп при обичайна физическа активност.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Клас II</strong></td><td style=\"font-size: 1em;\">Пациенти с <strong>ПХ</strong> с прояви на <strong>леко ограничение на физическата активност</strong>, липса на симптоми при покой, но наличие при обичайна физическа активност.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Клас III</strong></td><td style=\"font-size: 1em;\">Пациенти с <strong>ПХ</strong> с прояви на <strong>значимо ограничение на физическата активност</strong>, липса на симптоми при покой, наличие на умора, гръдна болка или синкоп при по-малка от обичайната физическа активност.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Клас IV</strong></td><td style=\"font-size: 1em;\">Пациенти с <strong>ПХ</strong> с <strong>невъзможност да извършват физическата активност без проява на симптоми</strong>, наличие на умора, гръдна болка или синкоп при покой. Минимални физически усилия водят до засилване на симптомите. Пациентите имат прояви на манифестна <strong>ДСН</strong>.</td></tr></tbody></table><ul><li style=\"font-size: 1em;\"><strong>Прогностично значение на СЗО класа:</strong></li><ul><li style=\"font-size: 1em;\">Средната преживяемост без ефективно лечение при пациенти с I и II Ф.КЛ е <strong>72 месеца</strong>.</li><li style=\"font-size: 1em;\">III Ф.КЛ – <strong>18 месеца</strong>.</li><li style=\"font-size: 1em;\">IV Ф.КЛ – <strong>6 месеца</strong>.</li></ul></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">СЪВРЕМЕННО ЛЕЧЕНИЕ НА ПАХ</h3><ul><li style=\"font-size: 1em;\">До днес все още <strong>липсва дифинитивно лечение</strong> за <strong>ПАХ</strong>.</li><li style=\"font-size: 1em;\">Цел на провежданото лечение е подобряване на <strong>очакваната преживяемост</strong>, <strong>физическото натоварване</strong> и <strong>качеството на живот</strong>.</li><li style=\"font-size: 1em;\">Конкретните схеми за лечение са насочени към повлияване на <strong>основното заболяване</strong>, <strong>степента на тежест</strong>, <strong>очакваната прогноза</strong>, наличието и достъпът до съответните лечебни опции (напр. <strong>белодробна трансплантация</strong>), икономически аспекти и хода на болестта на пациента и неговите очаквания.</li></ul><h4 style=\"font-size: 1.05em;\">1. Общи мерки</h4><ul><li style=\"font-size: 1em;\">Пациентите с <strong>ПХ</strong> трябва да получат компетентни съвети относно общите активности в ежедневието и да адаптират физическата си активност към наличното хронично, сериозно, застрашаващо живота им заболяване.</li><li style=\"font-size: 1em;\">Още поставянето на диагнозата определя ниво на <strong>социална изолация</strong>.</li><li style=\"font-size: 1em;\"><strong>Физическа активност:</strong></li><ul><li style=\"font-size: 1em;\">Физическата активност трябва да се <strong>ограничи до свободно от симптоми ниво</strong>.</li><li style=\"font-size: 1em;\">Подходящ режим на ежедневните занимания може да подобри качеството на живот и да намали честотата на поява на симптомите.</li></ul><li style=\"font-size: 1em;\"><strong>Хипоксия и височини:</strong></li><ul><li style=\"font-size: 1em;\"><strong>Хипоксията</strong> може да провокира <strong>вазоконстрикция</strong> при пациенти с <strong>ПХ</strong>.</li><li style=\"font-size: 1em;\">Пациентите с <strong>хронично белодробно сърце</strong> трябва да избягват пребиваването на <strong>големи височини</strong>.</li><li style=\"font-size: 1em;\">Бързото изкачване на височина от <strong>2000 m</strong> може да доведе до значимо влошаване на <strong>ДК функция</strong>.</li></ul></ul><h4 style=\"font-size: 1.05em;\">2. Подпомагащо лечение</h4><p style=\"font-size: 1em;\">Към подпомагащото лечение спадат мерки и прием на медикаменти, които са <strong>общовалидни за всички форми на ПХ</strong>.</p><table><tbody><tr><td style=\"font-size: 1em;\">Лечение</td><td style=\"font-size: 1em;\">Степен на препоръчителност</td><td style=\"font-size: 1em;\">Степен на доказателственост</td></tr><tr><td style=\"font-size: 1em;\">Антикоагуланти</td><td style=\"font-size: 1em;\">I*</td><td style=\"font-size: 1em;\">C</td></tr><tr><td style=\"font-size: 1em;\">Диуретици</td><td style=\"font-size: 1em;\">I</td><td style=\"font-size: 1em;\">C</td></tr><tr><td style=\"font-size: 1em;\">Дигиталис</td><td style=\"font-size: 1em;\">IIIb</td><td style=\"font-size: 1em;\">C</td></tr><tr><td style=\"font-size: 1em;\">Кислород</td><td style=\"font-size: 1em;\">IIIa<em></em></td><td style=\"font-size: 1em;\">C</td></tr><tr><td style=\"font-size: 1em;\">Калциеви антагонисти</td><td style=\"font-size: 1em;\">I<em></em>*</td><td style=\"font-size: 1em;\">C</td></tr><tr><td style=\"font-size: 1em;\">Балонна атриосептостомия</td><td style=\"font-size: 1em;\">IIa</td><td style=\"font-size: 1em;\">C</td></tr><tr><td style=\"font-size: 1em;\">Белодробна трансплантация</td><td style=\"font-size: 1em;\">I</td><td style=\"font-size: 1em;\">C</td></tr></tbody></table><blockquote style=\"font-size: 1em;\">*Валидно за <strong>ИПАХ</strong> и <strong>АПАХ</strong> при колагенози.</blockquote><blockquote style=\"font-size: 1em;\"><em></em>Препоръчва се съобразно изискванията за дълготрайна кислородотерапия.</blockquote><blockquote style=\"font-size: 1em;\"><strong><em>Само при пациенти с </em></strong><em>ИПАХ<strong>, изпълнили критериите за </strong>позитивен вазодилататорен отговор</em>*.</blockquote><p style=\"font-size: 1em;\"><b>2.1. Перорални антикоагуланти</b></p><ul><li style=\"font-size: 1em;\"><strong>ИПХ и фамилна ПАХ (ФПАХ):</strong> Индикация за антикоагулация с цел постигане на <strong>INR 1.5–2.5</strong>.</li><li style=\"font-size: 1em;\"><strong>Пациенти с протромботични рискови фактори:</strong> <strong>INR 2.0–3.5</strong>.</li><li style=\"font-size: 1em;\">Същите правила важат и за <strong>ПАХ</strong>, асоциирана с <strong>болести на колагена</strong>, <strong>HIV-инфекция</strong> и прием на апетитоподтискащи медикаменти, както и при <strong>ПАХ</strong> при <strong>венооклузивни заболявания</strong> и <strong>ДСН</strong>.</li><li style=\"font-size: 1em;\"><strong>Хронична тромбоемболична пулмонална хипертония:</strong> Лечението се назначава <strong>до края на живота</strong>, освен ако не са на лице противопоказания. Цел е постигане на <strong>INR 2.5–3.5</strong>.</li></ul><p style=\"font-size: 1em;\"><b>2.2. Диуретици</b></p><ul><li style=\"font-size: 1em;\">Пациенти с декомпенсирана <strong>ДСН</strong> имат <strong>задръжка на течности</strong>, водеща до повишено <strong>централно венозно налягане (ЦВН)</strong>, абдоминална органна конгестия, периферни отоци и <strong>асцит</strong>.</li><li style=\"font-size: 1em;\"><strong>Дългодействащите калий-съхраняващи медикаменти</strong> (антагонисти на <strong>алдостерона</strong>) са за предпочитано средство пред <strong>бримковите диуретици</strong>.</li><li style=\"font-size: 1em;\">При <strong>десностранна сърдечна недостатъчност</strong> и повишено <strong>ЦВН</strong> е необходимо често приложение на <strong>бримкови диуретици</strong>.</li></ul><p style=\"font-size: 1em;\"><b>.3. Дигиталисови препарати</b></p><ul><li style=\"font-size: 1em;\">При пациенти с <strong>тахикардия</strong> и <strong>предсърдно мъждене/трептене</strong> те се явяват медикамент на <strong>първи избор</strong>.</li></ul><p style=\"font-size: 1em;\"><b>2.4. Кислород</b></p><ul><li style=\"font-size: 1em;\">При повечето пациенти с <strong>ПАХ</strong> (с изключение на тези с вродени сърдечни пороци) се установява <strong>лекостепенна хипоксемия в покой</strong>.</li><li style=\"font-size: 1em;\">Необходимо е поддържане на постоянна <strong>кислородна сатурация над 90%</strong>.</li><li style=\"font-size: 1em;\">Индикациите за приложение на <strong>дълготрайно домашно кислородолечение</strong> се основават на общоприетите препоръки и формулирани критерии.</li></ul><p style=\"font-size: 1em;\"><b>2.5. Лечение с антибиотици, имунизации</b></p><ul><li style=\"font-size: 1em;\">Пациентите с <strong>ПАХ</strong> имат склонност към развитие на <strong>пневмония</strong>, което е причина за смърт в <strong>7%</strong> от случаите.</li><li style=\"font-size: 1em;\"><strong>Белодробните инфекции</strong> не се понасят добре и трябва да бъдат диагностицирани и лекувани възможно най-бързо.</li><li style=\"font-size: 1em;\">Препоръчва се ежегодна профилактична <strong>имунизация срещу грипни вируси и пневмококи</strong>.</li></ul><p style=\"font-size: 1em;\"><b>2.6. Контрацепция</b></p><ul><li style=\"font-size: 1em;\"><strong>Бременността</strong> и <strong>раждането</strong> при пациентки с <strong>ПАХ</strong> са свързани с <strong>повишена честота на клинично влошаване и смърт</strong>.</li><li style=\"font-size: 1em;\">На жени с <strong>ПАХ</strong>, които се намирата в детеродна възраст, се предписва <strong>надеждна контрацепция</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">3. Медикаменти, насочени към лечението на ПАХ</h4><p style=\"font-size: 1em;\">Специфичните медикаменти, прилагани за лечение на <strong>ПАХ</strong>, включват препарати, принадлежащи към групите на:</p><ul><li style=\"font-size: 1em;\"><strong>Калциевите антагонисти</strong></li><li style=\"font-size: 1em;\"><strong>Простаноидите</strong></li><li style=\"font-size: 1em;\"><strong>Ендотелинрецепторните антагонисти</strong></li><li style=\"font-size: 1em;\"><strong>Фосфодиестераза -5-инхибиторите</strong></li></ul><p style=\"font-size: 1em;\"><b>3.1. Високи дози калциеви антагонисти</b></p><ul><li style=\"font-size: 1em;\">Могат да доведат до много добро повлияване на <strong>хемодинамиката</strong> и натоварването в дългосрочен порядък.</li><li style=\"font-size: 1em;\">Прилагат се при пациенти с <strong>ИПАХ</strong> и <strong>фамилна ПАХ</strong>, които показват <strong>положителна белодробна вазореактивност</strong> в хода на провеждане на вазореактивен тест.</li></ul><p style=\"font-size: 1em;\"><b>3.2. Простаноиди</b></p><p style=\"font-size: 1em;\"><b>3.2.1. Интравенозен простациклин</b></p><ul><li style=\"font-size: 1em;\"><strong>Простациклинът</strong> е вазодилататорен <strong>PG</strong>, който се синтезира и освобождава от <strong>съдовия ендотел</strong>.</li><li style=\"font-size: 1em;\">Той е най-мощният ендогенен <strong>инхибитор на тромбоцитната агрегация</strong>.</li><li style=\"font-size: 1em;\">Притежава <strong>цитопротективен</strong> и <strong>антипролиферативен ефект</strong>, медиирани чрез вътреклетъчния <strong>цАМФ</strong>.</li><li style=\"font-size: 1em;\">Терапията с <strong>Epoprostenol</strong> се счита за средство на <strong>първи избор</strong> при пациенти с <strong>ПАХ NYHA IV ф.кл.</strong> и е последна форма на терапия, когато всички други са провалени.</li></ul><p style=\"font-size: 1em;\"><b>3.2.2. Интравенозен Iloprost</b></p><ul><li style=\"font-size: 1em;\"><strong>Интравенозният Iloprost</strong> е стабилен <strong>простациклинов аналог</strong> и е алтернатива на приложението на интравенозния <strong>Epoprostenol</strong>.</li></ul><p style=\"font-size: 1em;\"><b>3.2.3. Инхалаторен Iloprost (Ventavis)</b></p><ul><li style=\"font-size: 1em;\">След единична инхалаторна доза се наблюдава <strong>10-20% редукция</strong> на <strong>средното белодробно артериално налягане</strong>, която трае <strong>45-60 min</strong>.</li><li style=\"font-size: 1em;\"><strong>Кратката продължителност на ефекта</strong> изисква чести инхалации (<strong>от 6 до 9 пъти дневно</strong>) за постигане на продължителен ефект.</li><li style=\"font-size: 1em;\">Показва <strong>добра поносимост</strong>.</li></ul><p style=\"font-size: 1em;\"><b>3.3. Ендотелин рецепторни антагонисти</b></p><ul><li style=\"font-size: 1em;\"><strong>Двойно-селективният ендотелин рецепторен антагонист Bosentan</strong> (блокер на <strong>ендотелин (ЕТ) А- и ЕТВ-рецепторите</strong>) показва сигнификантни терапевтични ефекти.</li><li style=\"font-size: 1em;\">Прилага се при пациенти с <strong>ИПАХ</strong> и асоциирана със <strong>склеродермия ПАХ</strong> с <strong>NYHA III и IV ф. кл.</strong></li></ul><p style=\"font-size: 1em;\"><b>3.4. Инхибитори на фосфодиестераза - 5 (PDE5i)</b></p><ul><li style=\"font-size: 1em;\"><strong>Sildenafil</strong> е перорален активен, мощен и селективен <strong>инхибитор на фосфодиестераза тип 5</strong>.</li><li style=\"font-size: 1em;\">Упражнява фармакологичния си ефект чрез увеличение на интрацелуларната концентрация на <strong>cGMP</strong>.</li><li style=\"font-size: 1em;\">Увеличението на този нуклеотид довежда до <strong>релаксация</strong> и <strong>антипролиферативен ефект</strong> върху <strong>съдовите гладко-мускулни клетки</strong>.</li><li style=\"font-size: 1em;\">Показан при лечение на пациенти с <strong>ИПХ</strong> от <strong>NYHA III и IV ф. кл.</strong></li></ul><p style=\"font-size: 1em;\"><b>3.5. Комбинирано лечение</b></p><ul><li style=\"font-size: 1em;\">Представлява атрактивен вариант за противодействие на всички патофизиологични механизми, които са налице при <strong>ПАХ</strong>.</li><li style=\"font-size: 1em;\">Може да се прилага като <strong>едновременно се започне лечение с два (или повече) медикамента</strong>, или като се <strong>добави втори (или трети) медикамент</strong> към предишната терапия, която е отчетена като недостатъчно ефективна.</li></ul><h4 style=\"font-size: 1.05em;\">4. Други мерки</h4><p style=\"font-size: 1em;\"><b>4.1. Атриална септостомия</b></p><ul><li style=\"font-size: 1em;\">Вторично предизвикани <strong>предсърдни септални дефекти (атриална септостомия)</strong> може да подобрят прогнозата и симптомите при пациентите с <strong>ПАХ</strong>.</li></ul><p style=\"font-size: 1em;\"><b>4.2. Белодробна трансплантация</b></p><ul><li style=\"font-size: 1em;\">Показана е за пациенти, които <strong>не отговарят задоволително на медикаментозното лечение</strong>.</li></ul>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n</body>\r\n</html>";
